function setupF8Keyboard(){addEventListener("keydown",e=>{const target=e.target;if(target&&["INPUT","TEXTAREA","SELECT"].includes(target.tagName))return;const key=e.key.toLowerCase();if(e.key==="Escape"){closeTokenMenu();state.selected=null;state.selectedIds=[];renderTokens();updateSelectedMove();drawOnce();return}const tools={m:"select",p:"pan",r:"measure",a:"template",w:"wall",c:"prop",l:"light",o:"fog",t:"terrain",d:"drawing",n:"pin"};if(tools[key]&&(!["w","c","l","o","t","d","n"].includes(key)||state.canEdit)){e.preventDefault();setTool(tools[key]);return}const delta={ArrowLeft:[-1,0],ArrowRight:[1,0],ArrowUp:[0,-1],ArrowDown:[0,1]}[e.key];if(!delta||!state.selectedIds.length)return;e.preventDefault();const g=sceneSize().g,selected=state.tokens.filter(t=>state.selectedIds.includes(t.id)&&canMove(t));if(!selected.length)return;for(const t of selected){t.x=snap({x:t.x+delta[0]*g,y:t.y+delta[1]*g}).x;t.y=snap({x:t.x+delta[0]*g,y:t.y+delta[1]*g}).y}moveTokenGroup(selected).catch(err=>status(err.message||"movimento indisponivel","err"));drawOnce()})}
