function onUp(e){if(!pointer.down)return;const t=state.tokens.find(x=>x.id===pointer.id),fog=state.fogDraft,wall=state.wallDraft,prop=state.propDraft,light=state.lightDraft,drawing=state.drawingDraft,mode=pointer.mode;pointer.down=false;state.fogDraft=null;state.wallDraft=null;state.propDraft=null;state.lightDraft=null;state.drawingDraft=null;if(mode==="token"&&t){const moved=(pointer.group||[{id:t.id}]).map(item=>state.tokens.find(x=>x.id===item.id)).filter(Boolean);moveTokenGroup(moved).catch(e=>status(e.message,"err"))}if(mode==="templateMove"){const tpl=state.templates.find(x=>x.id===pointer.templateId);if(tpl)saveTemplatePlacement({id:tpl.id,kind:tpl.kind,x:tpl.x,y:tpl.y,directionDeg:tpl.directionDeg,distanceUnits:tpl.distanceUnits,angleDeg:tpl.angleDeg,widthUnits:tpl.widthUnits,color:tpl.color,label:tpl.label,hidden:tpl.hidden,lifecycle:tpl.lifecycle})}if(mode==="wall"&&wall&&Math.hypot(wall.x2-wall.x1,wall.y2-wall.y1)>=4)saveWall(wall).catch(err=>status(err.message,"err"));if(mode==="prop"&&prop&&prop.w>=4&&prop.h>=4)saveProp(prop).catch(err=>status(err.message,"err"));if(mode==="light"&&light&&Number(light.dimUnits)>0)saveLight(light).catch(err=>status(err.message,"err"));if(mode==="drawing"&&drawing&&drawing.points.length>1)saveDrawing(drawing).catch(err=>status(err.message,"err"));if(mode==="fog"&&fog)saveFog(fog);if(mode==="measure"){const attacker=state.tokens.find(x=>x.id===pointer.attackerTokenId),target=tokenAt(screenToWorld(e.clientX,e.clientY));const measure=buildAttackMeasure(attacker,target);if(measure){state.measure=measure;prepareMapAttack()}else setTimeout(()=>{if(state.measure&&!state.measure.attack){state.measure=null;drawOnce()}},1000)}if(mode==="template"){const d=state.templateDraft;state.templateDraft=null;if(d&&d.distanceUnits>0)saveTemplatePlacement(d);else drawOnce()}pointer.attackerTokenId=null;drawOnce()}
